def sanitize_username(name_id: str) -> str:
    """Sanitize username for Django user creation"""
    # Remove any characters that aren't alphanumeric, @, ., +, -, or _
    username = re.sub(r'[^\w.@+-]', '_', name_id)
    
    # Limit length to Django's username max length
    max_length = 150
    if len(username) > max_length:
        # Create a hash suffix to maintain uniqueness
        hash_suffix = hashlib.sha256(username.encode()).hexdigest()[:8]
        username = username[:max_length-9] + '_' + hash_suffix
    
    return username


def create_or_update_user(name_id: str, attributes: Dict[str, str]) -> User:
    """Create or update Django user from SAML data"""
    username = sanitize_username(name_id)
    
    # Extract common attributes with safe defaults
    email = attributes.get('email', attributes.get('mail', ''))
    first_name = attributes.get('givenName', attributes.get('firstName', ''))
    last_name = attributes.get('sn', attributes.get('surname', attributes.get('lastName', '')))
    
    # Sanitize email
    if email and len(email) > 254:
        email = email[:254]
    
    # Sanitize names
    if len(first_name) > 150:
        first_name = first_name[:150]
    if len(last_name) > 150:
        last_name = last_name[:150]
    
    # Get or create user
    user, created = User.objects.get_or_create(
        username=username,
        defaults={
            'email': email,
            'first_name': first_name,
            'last_name': last_name,
        }
    )
    
    # Update existing user attributes
    if not created:
        user.email = email
        user.first_name = first_name
        user.last_name = last_name
        user.save()
    
    return user


